+import {
+  createBrowserPluginService,
+  createBrowserTool,
+  definePluginEntry,
+  handleBrowserGatewayRequest,
+  registerBrowserCli,
+  type OpenClawPluginToolContext,
+  type OpenClawPluginToolFactory,
