+    .option("--fn <code>", "Function source, e.g. (el) => el.textContent")
+    .option("--ref <id>", "Ref from snapshot")
+    .option("--target-id <id>", "CDP target id (or unique prefix)")
+    .action(async (opts, cmd) => {
