+      await runBrowserCommand(async () => {
+        const result = await callBrowserRequest<{ running: boolean; tabs: BrowserTab[] }>(
+          parent,
+          {
+            method: "GET",
+            path: "/tabs",
+            query: resolveProfileQuery(profile),
+          },
+          { timeoutMs: BROWSER_MANAGE_REQUEST_TIMEOUT_MS },
