+        const tabs = result.tabs ?? [];
+        logBrowserTabs(tabs, parent?.json);
+      });
+    });
+
+  const tab = browser
+    .command("tab")
+    .description("Tab shortcuts (index-based)")
+    .action(async (_opts, cmd) => {
+      const parent = parentOpts(cmd);
